INSERT INTO "public"."acronym_traps" ("id", "exam", "name", "category", "subcategory", "exam_trap", "compare", "sort_order") VALUES (1, 'netplus', 'NAT vs PAT', 'Confusion Traps', 'NAT vs PAT', 'NAT = general concept. PAT = NAT + ports (most common in home networks).', '[{"term":"NAT","analogy":"Office building sharing one street address.","keyIdea":"Maps private IPs to public IPs.","fullName":"Network Address Translation","useCases":"Home router internet access."},{"term":"PAT","analogy":"Apartment number + building address.","keyIdea":"A type of NAT using port numbers.","fullName":"Port Address Translation","useCases":"Home Wi-Fi with many devices browsing."}]', 0), (2, 'netplus', 'TCP vs UDP', 'Confusion Traps', 'TCP vs UDP', '“Accuracy matters” → TCP. “Speed matters” → UDP.', '[{"term":"TCP","analogy":"Certified mail with signature.","keyIdea":"Reliable, ordered, guaranteed delivery.","fullName":"Transmission Control Protocol","useCases":"Web login, email, file transfer."},{"term":"UDP","analogy":"Throwing flyers into mailboxes.","keyIdea":"Fast, no guarantee delivery.","fullName":"User Datagram Protocol","useCases":"Gaming, streaming, VoIP."}]', 1), (3, 'netplus', 'VLAN vs Subnet', 'Confusion Traps', 'VLAN vs Subnet', 'VLAN = Layer 2 (switching). Subnet = Layer 3 (IP/routing).', '[{"term":"VLAN","analogy":"Different office departments in same building.","keyIdea":"Separates devices on same switch logically.","fullName":"Virtual LAN","useCases":"HR vs Sales on same switch."},{"term":"Subnet","analogy":"Different streets in city.","keyIdea":"Logical IP network separation.","fullName":"Subnetwork","useCases":"Organize IP addressing and routing."}]', 2), (4, 'netplus', 'Switch vs Router', 'Confusion Traps', 'Switch vs Router', 'Same network → Switch. Different networks → Router.', '[{"term":"Switch","analogy":"Mailroom inside building.","keyIdea":"Connects devices in same network.","fullName":"Network Switch","useCases":"Inside one LAN."},{"term":"Router","analogy":"Highway interchange.","keyIdea":"Connects different networks.","fullName":"Network Router","useCases":"LAN to internet, site-to-site."}]', 3), (5, 'netplus', 'IDS vs IPS', 'Confusion Traps', 'IDS vs IPS', 'IDS = passive alert. IPS = active blocking.', '[{"term":"IDS","analogy":"Security camera.","keyIdea":"Detects attacks only.","fullName":"Intrusion Detection System","useCases":"Alerting / SOC visibility."},{"term":"IPS","analogy":"Security guard stopping intruder.","keyIdea":"Detects AND blocks attacks.","fullName":"Intrusion Prevention System","useCases":"Inline traffic blocking."}]', 4), (6, 'netplus', 'DNS vs DHCP', 'Confusion Traps', 'DNS vs DHCP', '“Can’t reach website name” → DNS. “No IP assigned” → DHCP.', '[{"term":"DNS","analogy":"Phone contact list.","keyIdea":"Name → IP conversion.","fullName":"Domain Name System","useCases":"Resolving website names."},{"term":"DHCP","analogy":"Hotel room assignment.","keyIdea":"Gives IP addresses automatically.","fullName":"Dynamic Host Configuration Protocol","useCases":"Auto-config of clients."}]', 5), (7, 'netplus', 'HTTPS vs SSH', 'Confusion Traps', 'HTTPS vs SSH', 'Website login → HTTPS. Server admin terminal → SSH.', '[{"term":"HTTPS","analogy":"Locked envelope for web pages.","keyIdea":"Secure web browsing.","fullName":"Hypertext Transfer Protocol Secure","useCases":"Port 443 — websites."},{"term":"SSH","analogy":"Encrypted phone line to a server.","keyIdea":"Secure remote terminal access.","fullName":"Secure Shell","useCases":"Port 22 — server admin."}]', 6), (8, 'netplus', 'Cloud Models', 'Confusion Traps', 'SaaS vs PaaS vs IaaS', 'Use software → SaaS. Build apps → PaaS. Manage servers → IaaS.', '[{"term":"SaaS","analogy":"Streaming a movie.","keyIdea":"Use ready-made software.","fullName":"Software as a Service","useCases":"Gmail, Office 365."},{"term":"PaaS","analogy":"Renting a kitchen.","keyIdea":"Build apps on a platform.","fullName":"Platform as a Service","useCases":"App hosting environments."},{"term":"IaaS","analogy":"Renting an empty office.","keyIdea":"Rent servers, storage, networking.","fullName":"Infrastructure as a Service","useCases":"Virtual machines, cloud storage."}]', 7), (9, 'netplus', 'MFA vs SSO', 'Confusion Traps', 'MFA vs SSO', '“Extra verification” → MFA. “One login everywhere” → SSO.', '[{"term":"MFA","analogy":"Key + fingerprint.","keyIdea":"Multiple verification steps.","fullName":"Multi-Factor Authentication","useCases":"Password + phone code."},{"term":"SSO","analogy":"One badge opens many doors.","keyIdea":"One login for many apps.","fullName":"Single Sign-On","useCases":"Corporate app portal."}]', 8), (10, 'netplus', 'Wi-Fi Bands', 'Confusion Traps', '2.4 vs 5 vs 6 GHz', 'Wall penetration → 2.4 GHz. Speed → 5/6 GHz.', '[{"term":"2.4 GHz","analogy":"Big slow truck that goes far.","keyIdea":"Longer range, slower, more interference.","fullName":"2.4 GHz band","useCases":"Walls and distance."},{"term":"5 GHz","analogy":"Fast car, short trip.","keyIdea":"Faster, shorter range.","fullName":"5 GHz band","useCases":"Same-room high-speed Wi-Fi."},{"term":"6 GHz","analogy":"New empty highway.","keyIdea":"Newest, least congestion.","fullName":"6 GHz band (Wi-Fi 6E/7)","useCases":"Modern Wi-Fi 6E/7 devices."}]', 9), (11, 'netplus', 'Encryption Terms', 'Confusion Traps', 'TLS vs SSL vs AES', 'Modern secure web → TLS. Encryption standard → AES.', '[{"term":"TLS","analogy":"Modern armored truck.","keyIdea":"Modern encryption standard (HTTPS uses it).","fullName":"Transport Layer Security","useCases":"HTTPS, secure email, VPNs."},{"term":"SSL","analogy":"Older lock, replaced by TLS.","keyIdea":"Old outdated version (still mentioned in exams).","fullName":"Secure Sockets Layer","useCases":"Legacy terminology."},{"term":"AES","analogy":"The vault inside the armored truck.","keyIdea":"Symmetric encryption algorithm used inside TLS/Wi-Fi.","fullName":"Advanced Encryption Standard","useCases":"WPA2/WPA3, VPN payloads."}]', 10);